### 7. Direct vs Group Chat Handling

**Target Normalization (normalize.ts)**
```typescript
// IRC distinguishes by prefix
export function isChannelTarget(target: string): boolean {
  return target.startsWith("#") || target.startsWith("&");
}

// Telegram uses chat type inference
function resolveTelegramOutboundSessionRoute(params: {
  target: string;
  threadId?: string | number | null;
}) {
  const parsed = parseTelegramTarget(params.target);
  const isGroup = parsed.chatType === "group" || ...;
  const peer: RoutePeer = {
    kind: isGroup ? "group" : "direct",
    id: peerId,
  };
  // Returns with explicit chatType classification
  return {
    chatType: isGroup ? "group" : "direct",
    from: isGroup ? `telegram:group:${peerId}` : `telegram:${chatId}`,
  };
}
```

**Access Control (policy.ts)**
```typescript
// IRC: Groups require explicit groupPolicy + groupAllowFrom
// Does NOT fall back allowFrom → groupAllowFrom

// Telegram: Group access controlled via:
// - groupPolicy: "allowlist" | "open" | "disabled"
// - groupAllowFrom: user IDs per group
// - Per-topic allowFrom overrides in groups[groupId].topics
```

