### 11. Inbound Message Handling

**Flow (inbound.ts)**
```typescript
export async function handleIrcInbound(params: {
  message: IrcInboundMessage;
  account: ResolvedIrcAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  connectedNick?: string;
  sendReply?: (target: string, text: string, replyToId?: string) => void;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  // 1. Extract raw body
  const rawBody = message.text?.trim() ?? "";

  // 2. Determine if direct or group
  const isGroup = message.isGroup;

  // 3. Resolve access policy
  const {
    effectiveAllowFrom,
    effectiveGroupAllowFrom,
  } = resolveIrcEffectiveAllowlists({
    configAllowFrom: account.config.allowFrom ?? [],
    configGroupAllowFrom: account.config.groupAllowFrom ?? [],
    storeAllowList: pairing.getStoredAllowList(),
    dmPolicy: account.config.dmPolicy ?? "pairing",
  });

  // 4. Check pairing/allowlist
  const access = createChannelPairingController({
    core,
    channel: "irc",
    accountId: account.accountId,
  });

  // 5. Dispatch via framework
  await dispatchInboundReplyWithBase({
    /* payload */
  });
}
```

### 12. Outbound Message Handling

**Send Function (send.ts)**
```typescript
export async function sendMessageIrc(
  to: string,
  text: string,
  opts: SendIrcOptions = {},
): Promise<SendIrcResult> {
  const runtime = getIrcRuntime();
  const cfg = opts.cfg ?? runtime.config.loadConfig();
  const account = resolveIrcAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(`IRC not configured for account "${account.accountId}"`);
  }

  const target = resolveTarget(to, opts);
  const tableMode = resolveMarkdownTableMode({ cfg, channel: "irc", accountId: account.accountId });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty");
  }

  // Send through IRC client with chunking via chunkTextForOutbound
  return { messageId, target };
}
```

