82	  }
83	  const nickPart = prefix.match(/^([^!@]+)!([^@]+)@(.+)$/);
84	  if (nickPart) {
85	    return {
86	      nick: nickPart[1],
87	      user: nickPart[2],
88	      host: nickPart[3],
