89	      }),
90	    );
91	    transient.sendPrivmsg(target, payload);
92	    transient.quit("sent");
93	  }
94	
95	  recordIrcOutboundActivity(account.accountId);
96	
97	  return {
98	    messageId: makeIrcMessageId(),
99	    target,
100	  };
