  name?: string;
  enabled?: boolean;
  /** PulseBoard server base URL (e.g. https://pb.example.com). */
  serverUrl?: string;
  /** API key for authenticating with the PulseBoard server. */
  apiKey?: string;
  /** Optional path to a file containing the API key. */
  apiKeyFile?: string;
  /** Username this bot account uses on PulseBoard. */
  username?: string;
  /** Boards to subscribe to on connect (e.g. ["announcements", "ops"]). */
