/** Prefix used in target IDs to distinguish boards from DM usernames. */
export const BOARD_PREFIX = "board:" as const;

const VALID_TARGET_PATTERN = /^[A-Za-z0-9_\-./]+$/u;

/**
 * Returns true if the target refers to a board (group chat),
 * i.e. it starts with the "board:" prefix.
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith(BOARD_PREFIX);
}

/**
 * Extracts the bare board name from a target string, stripping the "board:" prefix.
 * Returns undefined when the target is not a valid board target.
 */
export function extractBoardName(target: string): string | undefined {
  const trimmed = target.trim();
  if (!trimmed.startsWith(BOARD_PREFIX)) {
    return undefined;
  }
  const name = trimmed.slice(BOARD_PREFIX.length).trim();
  return name && looksLikePulseBoardTargetId(name) ? name : undefined;
}

/**
 * Normalizes a raw target string into a canonical PulseBoard target.
 *
 * Accepted forms:
 *   - "board:<name>"       → "board:<name>" (group)
 *   - "pulseboard:board:<name>" → "board:<name>"
 *   - "pulseboard:<username>"   → "<username>" (DM)
 *   - "<username>"         → "<username>" (DM)
 *
 * Returns undefined for empty or invalid targets.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;

  // Strip the "pulseboard:" scheme prefix if present.
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Already a board: target.
  if (target.toLowerCase().startsWith("board:")) {
    const name = target.slice("board:".length).trim();
    if (!name || !looksLikePulseBoardTargetId(name)) {
      return undefined;
    }
    return `${BOARD_PREFIX}${name.toLowerCase()}`;
  }

  // Plain identifier — treat as DM username.
  if (!looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target.toLowerCase();
}

/**
 * Returns true if the raw string looks like a valid PulseBoard target ID
 * (board name or username): alphanumeric, hyphens, underscores, dots, slashes.
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  return Boolean(trimmed) && VALID_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalizes a single allowlist entry to lowercase, stripping known prefixes.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = String(raw).trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/**
 * Normalizes an array of allowlist entries, filtering out empty strings.
 */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Checks whether the message sender matches any entry in the allowlist.
 */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const sender = params.senderUsername.trim().toLowerCase();
  const allowFrom = new Set(
    params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  if (sender && allowFrom.has(sender)) {
    return { allowed: true, source: sender };
  }
  return { allowed: false };
}

