/**
 * Minimal PulseBoard HTTP client.
 *
 * PulseBoard REST API (fictional):
 *
 *   Auth header:  X-PulseBoard-Key: <apiKey>
 *
 *   GET  <serverUrl>/api/v1/events?since=<epochMs>&limit=<n>
 *        Response: { events: PulseBoardEvent[] }
 *
 *   POST <serverUrl>/api/v1/boards/<boardName>/messages
 *        Body:     { text: string, replyTo?: string }
 *        Response: { id: string }
 *
 *   POST <serverUrl>/api/v1/dm/<username>/messages
 *        Body:     { text: string, replyTo?: string }
 *        Response: { id: string }
 *
 *   GET  <serverUrl>/api/v1/me
 *        Response: { username: string }
 */

export type PulseBoardEvent = {
  id: string;
  /** "board_message" for board posts; "dm" for direct messages. */
  type: "board_message" | "dm";
  /** Only present when type="board_message". */
  boardName?: string;
  senderUsername: string;
  text: string;
  /** Unix epoch in milliseconds. */
  timestamp: number;
};

export type PulseBoardClientOptions = {
  serverUrl: string;
  apiKey: string;
  /** Timeout in milliseconds for each HTTP request. Default: 10000. */
  requestTimeoutMs?: number;
};

export type PulseBoardSendOptions = {
  replyTo?: string;
  timeoutMs?: number;
};

export type PulseBoardSendResult = {
  messageId: string;
};

function stripTrailingSlash(url: string): string {
  return url.replace(/\/+$/, "");
}

function makeAbortSignal(timeoutMs: number): AbortSignal {
  return AbortSignal.timeout(timeoutMs);
}

async function pbFetch(
  url: string,
  apiKey: string,
  init: RequestInit & { timeoutMs?: number },
): Promise<Response> {
  const { timeoutMs = 10000, ...rest } = init;
  const response = await fetch(url, {
    ...rest,
    headers: {
      "X-PulseBoard-Key": apiKey,
      "Content-Type": "application/json",
      Accept: "application/json",
      ...(rest.headers as Record<string, string> | undefined),
    },
    signal: makeAbortSignal(timeoutMs),
  });
  if (!response.ok) {
    const body = await response.text().catch(() => "");
    throw new Error(
      `PulseBoard API error ${response.status} ${response.statusText}${body ? `: ${body}` : ""}`,
    );
  }
  return response;
}

/**
 * Fetches new events since `sinceMs` (epoch ms).
 * Returns an empty array on network errors (caller handles reconnect logic).
 */
export async function pollPulseBoardEvents(
  opts: PulseBoardClientOptions,
  sinceMs: number,
  limit = 50,
): Promise<PulseBoardEvent[]> {
  const base = stripTrailingSlash(opts.serverUrl);
  const url = `${base}/api/v1/events?since=${sinceMs}&limit=${limit}`;
  const timeoutMs = opts.requestTimeoutMs ?? 10000;
  const response = await pbFetch(url, opts.apiKey, { method: "GET", timeoutMs });
  const json = (await response.json()) as { events?: PulseBoardEvent[] };
  return Array.isArray(json.events) ? json.events : [];
}

/**
 * Posts a text message to a named board.
 */
export async function postToPulseBoardBoard(
  opts: PulseBoardClientOptions,
  boardName: string,
  text: string,
  sendOpts?: PulseBoardSendOptions,
): Promise<PulseBoardSendResult> {
  const base = stripTrailingSlash(opts.serverUrl);
  const url = `${base}/api/v1/boards/${encodeURIComponent(boardName)}/messages`;
  const timeoutMs = sendOpts?.timeoutMs ?? opts.requestTimeoutMs ?? 10000;
  const body: Record<string, string> = { text };
  if (sendOpts?.replyTo) {
    body["replyTo"] = sendOpts.replyTo;
  }
  const response = await pbFetch(url, opts.apiKey, {
    method: "POST",
    body: JSON.stringify(body),
    timeoutMs,
  });
  const json = (await response.json()) as { id?: string };
  return { messageId: json.id ?? crypto.randomUUID() };
}

/**
 * Sends a direct message to a PulseBoard username.
 */
export async function sendPulseBoardDm(
  opts: PulseBoardClientOptions,
  recipientUsername: string,
  text: string,
  sendOpts?: PulseBoardSendOptions,
): Promise<PulseBoardSendResult> {
  const base = stripTrailingSlash(opts.serverUrl);
  const url = `${base}/api/v1/dm/${encodeURIComponent(recipientUsername)}/messages`;
  const timeoutMs = sendOpts?.timeoutMs ?? opts.requestTimeoutMs ?? 10000;
  const body: Record<string, string> = { text };
  if (sendOpts?.replyTo) {
    body["replyTo"] = sendOpts.replyTo;
  }
  const response = await pbFetch(url, opts.apiKey, {
    method: "POST",
    body: JSON.stringify(body),
    timeoutMs,
  });
  const json = (await response.json()) as { id?: string };
  return { messageId: json.id ?? crypto.randomUUID() };
}

/**
 * Fetches the authenticated account's profile to verify credentials.
 * Returns the username from the server on success.
 */
export async function fetchPulseBoardMe(
  opts: PulseBoardClientOptions & { timeoutMs?: number },
): Promise<{ username: string }> {
  const base = stripTrailingSlash(opts.serverUrl);
  const url = `${base}/api/v1/me`;
  const timeoutMs = opts.timeoutMs ?? opts.requestTimeoutMs ?? 8000;
  const response = await pbFetch(url, opts.apiKey, { method: "GET", timeoutMs });
  const json = (await response.json()) as { username?: string };
  if (!json.username) {
    throw new Error("PulseBoard /api/v1/me returned no username");
  }
  return { username: json.username };
}

