import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { postToPulseBoardBoard, sendPulseBoardDm } from "./client.js";
import { isBoardTarget, extractBoardName, normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseBoardMessagingTarget(to);
  if (!normalized) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }
  return normalized;
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl, apiKey, and username in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to);
  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);

  if (!prepared.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const clientOpts = {
    serverUrl: account.serverUrl,
    apiKey: account.apiKey,
  };

  let result: { messageId: string };

  if (isBoardTarget(target)) {
    // Group chat: post to a named board.
    const boardName = extractBoardName(target);
    if (!boardName) {
      throw new Error(`Invalid PulseBoard board target: ${target}`);
    }
    result = await postToPulseBoardBoard(clientOpts, boardName, prepared, {
      replyTo: opts.replyTo,
    });
  } else {
    // Direct message: send to a username.
    result = await sendPulseBoardDm(clientOpts, target, prepared, {
      replyTo: opts.replyTo,
    });
  }

  recordPulseBoardOutboundActivity(account.accountId);

  return {
    messageId: result.messageId,
    target,
  };
}

