import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { pollPulseBoardEvents, type PulseBoardEvent } from "./client.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { BOARD_PREFIX } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/** Converts a raw PulseBoardEvent into the internal inbound message format. */
export function resolvePulseBoardInboundMessage(
  event: PulseBoardEvent,
  selfUsername: string,
): PulseBoardInboundMessage | null {
  // Ignore our own messages.
  if (event.senderUsername.toLowerCase() === selfUsername.toLowerCase()) {
    return null;
  }

  if (event.type === "board_message" && event.boardName) {
    return {
      messageId: event.id,
      target: `${BOARD_PREFIX}${event.boardName}`,
      senderUsername: event.senderUsername,
      text: event.text,
      timestamp: event.timestamp,
      isGroup: true,
      boardName: event.boardName,
    };
  }

  if (event.type === "dm") {
    return {
      messageId: event.id,
      target: event.senderUsername,
      senderUsername: event.senderUsername,
      text: event.text,
      timestamp: event.timestamp,
      isGroup: false,
    };
  }

  return null;
}

/** Sleeps for `ms` milliseconds, resolving early if the abort signal fires. */
function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  return new Promise((resolve) => {
    if (signal?.aborted) {
      resolve();
      return;
    }
    const timer = setTimeout(resolve, ms);
    signal?.addEventListener("abort", () => {
      clearTimeout(timer);
      resolve();
    });
  });
}

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl, apiKey, and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] starting PulseBoard provider (${account.serverUrl}) as ${account.username}`,
  );

  const clientOpts = {
    serverUrl: account.serverUrl,
    apiKey: account.apiKey,
  };

  let stopped = false;
  // Track the highest event timestamp seen to avoid re-processing.
  let sinceMs = Date.now();

  // Start the polling loop as a background task.
  const pollLoop = async () => {
    while (!stopped && !opts.abortSignal?.aborted) {
      try {
        const events = await pollPulseBoardEvents(clientOpts, sinceMs);

        for (const event of events) {
          if (stopped || opts.abortSignal?.aborted) {
            break;
          }
          // Advance the cursor so we never re-process the same event.
          if (event.timestamp >= sinceMs) {
            sinceMs = event.timestamp + 1;
          }

          const message = resolvePulseBoardInboundMessage(event, account.username);
          if (!message) {
            continue;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          if (opts.onMessage) {
            await opts.onMessage(message);
          } else {
            await handlePulseBoardInbound({
              message,
              account,
              config: cfg,
              runtime,
              sendReply: async (target, text) => {
                const { sendMessagePulseBoard } = await import("./send.js");
                await sendMessagePulseBoard(target, text, {
                  accountId: account.accountId,
                });
                opts.statusSink?.({ lastOutboundAt: Date.now() });
                core.channel.activity.record({
                  channel: "pulseboard",
                  accountId: account.accountId,
                  direction: "outbound",
                });
              },
              statusSink: opts.statusSink,
            });
          }
        }
      } catch (err) {
        if (!stopped && !opts.abortSignal?.aborted) {
          logger.error(`[${account.accountId}] poll error: ${String(err)}`);
        }
      }

      if (!stopped && !opts.abortSignal?.aborted) {
        await sleep(account.pollIntervalMs, opts.abortSignal);
      }
    }
  };

  // Start without blocking the caller.
  void pollLoop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

